1	/**
2	 * Layerinfinite — api/index.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Main Hono application entry point.
5	 *
6	 * Middleware order:
7	 *   1. Global: logger, CORS, secureHeaders, prettyJSON
8	 *   2. Rate limit on all /v1 routes (tiered by customer tier)
9	 *   3. Admin routes: authMiddleware + adminAuthMiddleware
10	 *   4. Agent routes: authMiddleware (or devAuthMiddleware)
11	 *   5. validateActionMiddleware on log-outcome only
12	 * ══════════════════════════════════════════════════════════════
13	 */
14	
15	import 'dotenv/config';
16	
17	import { Hono } from 'hono';
18	import { cors } from 'hono/cors';
19	import { logger } from 'hono/logger';
20	import { secureHeaders } from 'hono/secure-headers';
21	import { prettyJSON } from 'hono/pretty-json';
22	import { serve } from '@hono/node-server';
23	import { getOutcomeQueueMode, startDurableQueueWorker, getDurableQueueHealth } from './lib/outcome-ingest-queue.js';
24	
25	const REQUIRED_ENV_VARS = [
26	    'SUPABASE_URL',
27	    'SUPABASE_SERVICE_ROLE_KEY',
28	    'SUPABASE_ANON_KEY',
29	];
30	
31	if (process.env.NODE_ENV === 'production') {
32	    REQUIRED_ENV_VARS.push('LAYERINFINITE_INTERNAL_SECRET');
33	}
34	
35	const missing = REQUIRED_ENV_VARS.filter(
36	    v => !process.env[v]
37	);
38	
39	if (missing.length > 0) {
40	    console.error(
41	        '❌ FATAL: Missing required environment variables:\n' +
42	        missing.map(v => `  - ${v}`).join('\n') +
43	        '\n\nCopy .env.example to .env and fill in values.\n' +
44	        'See PRODUCTION_CHECKLIST.md for instructions.'
45	    );
46	    process.exit(1);
47	}
48	
49	// In development, LAYERINFINITE_DEV_API_KEY is optional 
50	// (falls back to real auth). Never required in production.
51	if (process.env.NODE_ENV !== 'production' &&
52	    !process.env.LAYERINFINITE_DEV_API_KEY) {
53	    console.warn(
54	        '⚠️  LAYERINFINITE_DEV_API_KEY not set. ' +
55	        'Dev bypass will require real API keys. ' +
56	        'Set it in .env for local testing convenience.'
57	    );
58	}
59	
60	import { authMiddleware, devAuthMiddleware } from './middleware/auth.js';
61	import { adminAuthMiddleware } from './middleware/admin-auth.js';
62	import { rateLimitMiddleware } from './middleware/rate-limit.js';
63	import { validateActionMiddleware } from './middleware/validate-action.js';
64	
65	import { logOutcomeRouter } from './routes/log-outcome.js';
66	import { getScoresRouter } from './routes/get-scores.js';
67	import { getPatternsRouter } from './routes/get-patterns.js';
68	import { auditRouter } from './routes/audit.js';
69	import { actionsRouter } from './routes/admin/actions.js';
70	import { reinstateAgentRouter } from './routes/admin/reinstate-agent.js';
71	import { reinstateSandboxRouter } from './routes/admin/reinstate-sandbox.js';
72	import { testNotificationRouter } from './routes/admin/test-notification.js';
73	import { triggerTrainingRoute } from './routes/admin/trigger-training.js';
74	import { restoreTrustSnapshotRouter } from './routes/admin/restore-trust-snapshot.js';
75	import { embeddingDriftRouter } from './routes/admin/embedding-drift.js';
76	import { modelHistoryRouter } from './routes/model-history.js';
77	import { userAuthMiddleware } from './middleware/user-auth.js';
78	import { apiKeysRouter } from './routes/auth/api-keys.js';
79	import { meRouter } from './routes/auth/me.js';
80	import { outcomeFeedbackRouter } from './routes/outcome-feedback.js';
81	import { simulateRouter } from './routes/simulate.js';
82	import contractsRoute from './routes/contracts.js';
83	import discrepancyRoute from './routes/discrepancy.js';
84	import pendingSignalsRoute from './routes/pending-signals.js';
85	import businessWebhookRoute from './routes/business-webhook.js';
86	import webhookRoute from './routes/webhook.js';
87	import { getRecommendationsRouter } from './routes/get-recommendations.js';
88	import { observeRouter } from './routes/observe.js';
89	import { importRouter } from './routes/import.js';
90	
91	// ── PORT: Railway injects PORT, fallback to API_PORT, then 3000 ──
92	const PORT = parseInt(process.env.PORT ?? process.env.API_PORT ?? '3000', 10);
93	
94	// ── FATAL: Dev bypass CANNOT be active in production ──────────
95	if (process.env.NODE_ENV === 'production' &&
96	    process.env.LAYERINFINITE_DEV_BYPASS === 'true') {
97	    console.error('FATAL: Dev bypass cannot be active in production. Set LAYERINFINITE_DEV_BYPASS=false.');
98	    process.exit(1);
99	}
100	
101	// ── Create app ────────────────────────────────────────────────
102	const app = new Hono();
103	
104	// ── CORS: env-driven origins ──────────────────────────────────
105	const allowedOrigins = process.env.ALLOWED_ORIGINS
106	    ? process.env.ALLOWED_ORIGINS.split(',').map(o => o.trim()).filter(Boolean)
107	    : ['http://localhost:3000', 'http://localhost:5173'];
108	
109	// Warn loudly in production if no https:// origin is configured
110	if (process.env.NODE_ENV === 'production') {
111	    const hasHttps = allowedOrigins.some(o => o.startsWith('https://'));
112	    if (!hasHttps) {
113	        console.warn(
114	            '⚠️  CORS WARNING: ALLOWED_ORIGINS contains no https:// URL in production.\n' +
115	            '   Current origins: ' + allowedOrigins.join(', ') + '\n' +
116	            '   All browser requests from your dashboard will be blocked.\n' +
117	            '   Set ALLOWED_ORIGINS=https://your-dashboard.vercel.app on Railway.'
118	        );
119	    }
120	}
121	
122	// ── Global middleware ─────────────────────────────────────────
123	app.use('*', logger());
124	app.use('*', secureHeaders());
125	app.use('*', cors({
126	    origin: (origin) => allowedOrigins.includes(origin) ? origin : null,
127	    allowHeaders: ['X-API-Key', 'X-Admin-Key', 'Authorization', 'Content-Type'],
128	    allowMethods: ['GET', 'POST', 'PUT', 'DELETE', 'OPTIONS'],
129	    exposeHeaders: ['X-RateLimit-Limit', 'X-RateLimit-Remaining', 'X-RateLimit-Reset'],
130	}));
131	app.use('*', prettyJSON());
132	
133	// ── Global Timeout Middleware ─────────────────────────────────
134	const REQUEST_TIMEOUT_MS = parseInt(process.env.REQUEST_TIMEOUT_MS ?? '10000', 10);
135	
136	app.use('*', async (c, next) => {
137	    if (
138	        c.req.path === '/health' ||
139	        c.req.path === '/health/deep' ||
140	        c.req.path === '/'
141	    ) {
142	        return next();
143	    }
144	
145	    const controller = new AbortController();
146	    let timeoutId: ReturnType<typeof setTimeout> | null = null;
147	
148	    const timeoutPromise = new Promise<never>((_, reject) => {
149	        const onAbort = () => reject(new Error('TIMEOUT'));
150	        controller.signal.addEventListener('abort', onAbort, { once: true });
151	        // { once: true } automatically removes the listener after it fires.
152	        // This prevents listener accumulation on the happy path.
153	    });
154	
155	    timeoutId = setTimeout(
156	        () => controller.abort(),
157	        REQUEST_TIMEOUT_MS
158	    );
159	
