7	function parseBoolean(value: string | undefined, defaultValue = false): boolean {
8	    if (value === undefined) return defaultValue;
9	    const normalized = value.trim().toLowerCase();
10	    return normalized === '1' || normalized === 'true' || normalized === 'yes' || normalized === 'on';
11	}
12	
13	function parseFiniteNumber(value: string | undefined, defaultValue: number): number {
14	    if (value === undefined) return defaultValue;
15	    const parsed = Number(value);
16	    if (!Number.isFinite(parsed)) return defaultValue;
17	    return parsed;
18	}
19	
20	function parsePositiveInt(value: string | undefined, defaultValue: number): number {
21	    const parsed = Math.floor(parseFiniteNumber(value, defaultValue));
22	    if (parsed <= 0) return defaultValue;
23	    return parsed;
24	}
25	
26	function clamp(value: number, min: number, max: number): number {
27	    return Math.max(min, Math.min(max, value));
28	}
29	
30	function clamp01(value: number): number {
31	    return clamp(value, 0, 1);
32	}
