34	export interface RecommendationRolloutConfig {
35	    noiseAwareGateEnabled: boolean;
36	    simulationShadowEnabled: boolean;
37	    simulationConfidenceCeilingEnabled: boolean;
38	    simulationExploitGateEnabled: boolean;
39	
40	    normalWarmupSamples: number;
41	    stableSamples: number;
42	    highConfidenceSamples: number;
43	
44	    noisyWarmupSamples: number;
45	    noisyStableSamples: number;
46	    noisyHighConfidenceSamples: number;
47	
48	    noiseWinRateLower: number;
49	    noiseWinRateUpper: number;
50	    noiseGapMax: number;
51	    noiseScoreThreshold: number;
52	
53	    simulationShadowBlendCap: number;
54	    simulationShadowBlendUntilSamples: number;
55	    simulationShadowDecisionLookback: number;
56	    simulationShadowRecentPerAction: number;
57	
58	    simulationConfidenceCeiling: number;
59	    simulationExploitGateMinSamples: number;
60	}
61	
62	export function getRecommendationRolloutConfig(
63	    env: NodeJS.ProcessEnv = process.env,
64	): RecommendationRolloutConfig {
65	    const noiseWinRateLower = clamp01(parseFiniteNumber(env.LI_NOISE_WIN_RATE_LOWER, 0.40));
66	    const noiseWinRateUpper = clamp01(
67	        parseFiniteNumber(env.LI_NOISE_WIN_RATE_UPPER, Math.max(0.55, noiseWinRateLower + 0.01)),
68	    );
69	
70	    return {
71	        // Strict rollout defaults: all new gates are disabled unless explicitly enabled.
72	        noiseAwareGateEnabled: parseBoolean(env.LI_FEATURE_NOISE_AWARE_EVIDENCE_GATE_V1, false),
73	        simulationShadowEnabled: parseBoolean(env.LI_FEATURE_SIMULATION_SHADOW_V1, false),
74	        simulationConfidenceCeilingEnabled: parseBoolean(env.LI_FEATURE_SIMULATION_CONFIDENCE_CEILING_V1, false),
75	        simulationExploitGateEnabled: parseBoolean(env.LI_FEATURE_SIMULATION_EXPLOIT_GATE_V1, false),
76	
77	        normalWarmupSamples: MIN_SAMPLES,
78	        stableSamples: MIN_SAMPLES_STABLE,
79	        highConfidenceSamples: MIN_SAMPLES_HIGH_CONFIDENCE,
80	
81	        noisyWarmupSamples: Math.max(
82	            MIN_SAMPLES,
83	            parsePositiveInt(env.LI_NOISY_WARMUP_MIN_SAMPLES, 30),
84	        ),
85	        noisyStableSamples: Math.max(
86	            MIN_SAMPLES_STABLE,
87	            parsePositiveInt(env.LI_NOISY_STABLE_MIN_SAMPLES, MIN_SAMPLES_STABLE),
88	        ),
89	        noisyHighConfidenceSamples: Math.max(
90	            MIN_SAMPLES_HIGH_CONFIDENCE,
91	            parsePositiveInt(env.LI_NOISY_HIGH_CONFIDENCE_SAMPLES, 150),
92	        ),
93	
94	        noiseWinRateLower,
95	        noiseWinRateUpper: Math.max(noiseWinRateLower + 0.01, noiseWinRateUpper),
96	        noiseGapMax: clamp(parseFiniteNumber(env.LI_NOISE_GAP_MAX, 0.10), 0.01, 1),
97	        noiseScoreThreshold: clamp01(parseFiniteNumber(env.LI_NOISE_SCORE_THRESHOLD, 0.55)),
98	
99	        simulationShadowBlendCap: clamp(
100	            parseFiniteNumber(env.LI_SIMULATION_SHADOW_BLEND_CAP, 0.20),
101	            0,
102	            0.5,
103	        ),
104	        simulationShadowBlendUntilSamples: Math.max(
105	            MIN_SAMPLES,
106	            parsePositiveInt(env.LI_SIMULATION_SHADOW_BLEND_UNTIL_SAMPLES, 30),
107	        ),
108	        simulationShadowDecisionLookback: parsePositiveInt(
109	            env.LI_SIMULATION_SHADOW_DECISION_LOOKBACK,
110	            200,
111	        ),
112	        simulationShadowRecentPerAction: clamp(
113	            parsePositiveInt(env.LI_SIMULATION_SHADOW_RECENT_PER_ACTION, 5),
114	            1,
115	            20,
116	        ),
117	
118	        simulationConfidenceCeiling: clamp01(
119	            parseFiniteNumber(env.LI_SIMULATION_CONFIDENCE_CEILING, 0.65),
120	        ),
121	        simulationExploitGateMinSamples: Math.max(
122	            MIN_SAMPLES,
123	            parsePositiveInt(env.LI_SIMULATION_EXPLOIT_GATE_MIN_SAMPLES, 60),
124	        ),
125	    };
126	}
