108	function normalizeXReadGroupReply(reply: unknown): OutcomeIngestStreamMessage[] {
109	    if (!Array.isArray(reply)) return [];
110	
111	    const messages: OutcomeIngestStreamMessage[] = [];
112	    for (const streamChunk of reply) {
113	        if (!Array.isArray(streamChunk) || streamChunk.length < 2) continue;
114	        const entries = streamChunk[1];
115	        if (!Array.isArray(entries)) continue;
116	
117	        for (const entry of entries) {
118	            if (!Array.isArray(entry) || entry.length < 2) continue;
119	            const id = String(entry[0] ?? '');
120	            const fields = entry[1];
121	            if (!id || !Array.isArray(fields)) continue;
122	
123	            for (let i = 0; i < fields.length; i += 2) {
124	                const key = String(fields[i] ?? '');
125	                const value = String(fields[i + 1] ?? '');
126	                if (key === 'payload') {
127	                    messages.push({ id, payload: value });
128	                    break;
129	                }
130	            }
131	        }
132	    }
133	
134	    return messages;
135	}
