143	    const entries = reply[1];
144	
145	    if (!Array.isArray(entries)) {
146	        return { nextStartId, messages: [] };
147	    }
148	
149	    const messages: OutcomeIngestStreamMessage[] = [];
150	    for (const entry of entries) {
